def authenticate_user(username, password):
    """Legacy auth - checks against local DB."""
    user = db.query('SELECT * FROM users WHERE username = ?', username)
    if user and bcrypt.verify(password, user.password_hash):
        return create_session(user)
    return None

def create_session(user):
    """Creates a session token in the sessions table."""
    token = secrets.token_hex(32)
    db.execute('INSERT INTO sessions (token, user_id) VALUES (?, ?)', token, user.id)
    return {'token': token, 'user_id': user.id}

def validate_session(token):
    """Validates session against local DB."""
    session = db.query('SELECT * FROM sessions WHERE token = ?', token)
    if session and not is_expired(session):
        return session.user_id
    return None

def logout(token):
    db.execute('DELETE FROM sessions WHERE token = ?', token)
```

